content:
/* Activity Monitor */
  #main-wrap{display:flex;flex:1;overflow:hidden;min-height:0}
  #activity-panel{width:0;overflow:hidden;transition:width .3s ease;background:var(--surface);border-left:1px solid var(--border);display:flex;flex-direction:column;flex-shrink:0}
  #activity-panel.open{width:340px}
  .act-header{padding:10px 14px;font-size:13px;font-weight:600;color:var(--accent);border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center}
  .act-header button{background:none;border:none;color:var(--dim);cursor:pointer;font-size:18px;line-height:1}
  .act-header button:hover{color:var(--text)}
  .act-section{padding:8px 14px;border-bottom:1px solid var(--border);flex-shrink:0}
  .act-section h3{font-size:11px;color:var(--dim);text-transform:uppercase;letter-spacing:1px;margin-bottom:4px}
  .act-plan-item{font-size:12px;padding:2px 0;display:flex;gap:6px;align-items:baseline;color:var(--dim)}
  .act-plan-item.done{color:var(--ma)}
  .act-plan-item.active{color:var(--accent)}
  .act-plan-item .icon{min-width:14px;text-align:center;font-size:11px}
  #act-feed{flex:1;overflow-y:auto;padding:8px 14px}
  .act-entry{font-size:11px;padding:3px 0;display:flex;gap:6px;color:var(--dim);border-bottom:1px solid rgba(48,54,61,.3)}
  .act-entry .act-time{min-width:46px;font-size:10px;opacity:.7;font-family:monospace}
  .act-entry .act-icon{min-width:16px;text-align:center}
  .act-entry .act-text{flex:1;word-break:break-word}
  .act-entry.tool-call{color:var(--accent)}
  .act-entry.tool-result{color:var(--ma)}
  .act-entry.llm-call{color:#d2a8ff}
  .act-entry.error{color:var(--err)}
  .act-toggle{cursor:pointer;margin-left:auto;font-size:12px;color:var(--dim);background:none;border:1px solid var(--border);border-radius:6px;padding:4px 12px;font-weight:600}
  .act-toggle:hover{color:var(--accent);border-color:var(--accent)}
  .act-toggle.active{color:var(--accent);border-color:var(--accent);background:rgba(88,166,255,.1)}
